$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_83112255bb4233cad4276eab160483e8'] = 'Attiva o disattiva il pulitore. Quando è disattivato, l’URL cron e il pulsante di esecuzione manuale non elimineranno le vecchie statistiche. Usa questo interruttore per mantenere il modulo installato ma fermare temporaneamente ogni attività di pulizia.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_896e1fd6ab19d8bbd2f58f989fbaac76'] = 'Giorni di conservazione per le statistiche di connessione';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_b878a67f82524d412dae79ad597ff402'] = 'Le righe più vecchie di questo valore saranno rimosse da connections, connections_source e connections_page.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_5ee406d769ac3887713d3308a0d01601'] = 'Inserisci il numero di giorni per cui mantenere le statistiche grezze dei visitatori PrestaShop. Esempio: 60 significa che il modulo conserva gli ultimi 60 giorni ed elimina i record più vecchi da ps_connections, ps_connections_source e ps_connections_page. Non impostare 1 se non sei sicuro di non aver bisogno delle statistiche recenti.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_1300769d8d72fc8218b40772f1c25efc'] = 'Dimensione batch';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_631c4c75cb36e0fcee3da42ef67e730e'] = 'Numero massimo di connessioni elaborate in un batch.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_acbc6e359c79ace4ef9b5398148c13e2'] = 'Inserisci quanti record principali di connessione possono essere elaborati in un batch interno. Valori più piccoli sono più sicuri su hosting deboli ma richiedono più esecuzioni cron. Valori più grandi puliscono più velocemente ma possono mantenere blocchi database più a lungo. Valore iniziale consigliato: da 1000 a 5000; aumenta solo dopo aver testato il tempo di esecuzione.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_2806977593fb4c23003cc11306b135d1'] = 'Batch massimi per esecuzione';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d31a094a19379b58b63b51ef0f9d9362'] = 'Limita quanto lavoro può svolgere una singola esecuzione cron.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_e221a5a91ea62a43adc5bb15614eb578'] = 'Inserisci quanti batch possono essere eseguiti durante una singola esecuzione cron. Il totale possibile di record principali eliminati è circa Dimensione batch moltiplicata per Batch massimi per esecuzione. Esempio: 5000 e 10 significa fino a circa 50000 record in una esecuzione cron. Riduci questo valore se il negozio rallenta durante la pulizia.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a1a47524ffa9c839887703df1fbe70a3'] = 'Svuota ps_layered_filter_block';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_924684322fe68e56ef9205e7f480f598'] = 'Svuota la cache del blocco di ricerca facet/layered usando TRUNCATE TABLE. La tabella viene ricreata vuota da MySQL/MariaDB.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_92a6452eb793565a92aa28e5f9a3f2e5'] = 'Abilita solo se ps_layered_filter_block cresce troppo o contiene cache obsoleta della ricerca facet. Non elimina prodotti, categorie o l’indice prezzi layered. Dopo la pulizia PrestaShop o il modulo di ricerca facet può ricostruire la cache se necessario.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_bf45506cce2494894a9df6ff4bdf83ae'] = 'Aggrega le statistiche delle sorgenti di traffico prima dell’eliminazione';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_d7e1a0c7e7973ebcde37aa659525105d'] = 'Salva statistiche giornaliere riepilogate delle sorgenti di traffico prima di eliminare le righe grezze.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ae729759e10d7a626a8622321932a1f4'] = 'Quando abilitato, il modulo salva un piccolo riepilogo giornaliero prima di rimuovere le statistiche grezze PrestaShop. Mantiene conteggi come visite, visualizzazioni pagina, dominio sorgente e valori UTM. Non salva indirizzi IP, URL referrer completi o stringhe user-agent. Disabilitalo se vuoi solo eliminare e non hai bisogno di riepiloghi storici.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_ce2b282d224153cccd645f28504ab4e2'] = 'Giorni di conservazione statistiche aggregate';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_c3b4d14f7bff29c221039e891918f2dd'] = 'Per quanto tempo deve essere mantenuta la piccola tabella di riepilogo giornaliero.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_a97a6a6ab09f48206a543fdc7321bb60'] = 'Inserisci per quanti giorni i riepiloghi aggregati delle sorgenti di traffico devono restare nella tabella del modulo. Esempio: 730 conserva circa due anni di riepiloghi giornalieri. Questa impostazione riguarda solo ps_jooim_dbcleaner_traffic_daily, non le tabelle statistiche originali di PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>jooim_dbcleaner_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout blocco obsoleto in secondi';
