$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_c3b4d14f7bff29c221039e891918f2dd'] = 'Per quanto tempo deve essere mantenuta la piccola tabella di riepilogo giornaliero.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_a97a6a6ab09f48206a543fdc7321bb60'] = 'Inserisci per quanti giorni i riepiloghi aggregati delle sorgenti di traffico devono restare nella tabella del modulo. Esempio: 730 conserva circa due anni di riepiloghi giornalieri. Questa impostazione riguarda solo ps_jooim_dbcleaner_traffic_daily, non le tabelle statistiche originali di PrestaShop.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_4d4c70d739ad72835a8b62a81e07c611'] = 'Timeout blocco obsoleto in secondi';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_ef4f59605eb7e54ec7df26e3755b7edf'] = 'Protezione contro due processi di pulizia eseguiti contemporaneamente.';
$_MODULE['<{jooim_dbcleaner}prestashop>footer_attribution_2c1824ea38ec688698a26f01a46e6b16'] = 'Inserisci il numero di secondi dopo cui un blocco di pulizia non terminato viene considerato abbandonato. Protegge il database da due esecuzioni cron simultanee. Valore consigliato: 7200. Riduci solo se il cron termina sempre rapidamente.';
